let email = $input.first().json.email || "";
let username = email.split('@')[0];

return [
  {
    json: {
      text: username
    }
  }
];

// 1. Взимаме индекса на текущото завъртане на ГОЛЕМИЯ цикъл
// Използваме 'Loop Over Items' (първия ти голям цикъл), за да разберем на кой потребител сме в момента
const currentIteration = $('Loop Over Items').context.currentIteration;

// 2. Взимаме данните от Edit Fields5, но филтрирани САМО за това конкретно завъртане
const currentInputs = $input.all().filter(item => item.pairedItem && item.pairedItem.iteration === currentIteration);

// Застраховка: ако n8n няма pairedItem информация, вземи просто текущия входящ масив за тази итерация
const itemsToProcess = currentInputs.length > 0 ? currentInputs : $input.all();

// 3. Обхождаме само филтрираните елементи
return itemsToProcess.map(item => {
  let myRowText = "";

  if (item.json && item.json.incoming_message) {
    myRowText = typeof item.json.incoming_message === 'object' 
      ? (item.json.incoming_message.row || JSON.stringify(item.json.incoming_message)) 
      : item.json.incoming_message;
  } else if (item.json) {
    const firstValue = Object.values(item.json)[0];
    myRowText = typeof firstValue === 'object' ? JSON.stringify(firstValue) : firstValue;
  }

  if (!myRowText || myRowText === "undefined") {
    myRowText = "Празно съобщение / Грешка при четене";
  }

  const formattedOutput = `\n\n● ${myRowText}\n\n`;
  const base64Data = Buffer.from(formattedOutput, 'utf-8').toString('base64');

  return {
    json: { 
      incoming_message: myRowText,
      myRow: formattedOutput
    },
    binary: {
      data: { 
        data: base64Data,
        mimeType: 'text/plain',
        fileName: 'temp_row.txt'
      }
    }
  };
});
